      "non_canonical_erc20": "Fee-on-transfer, rebasing, non-approve-0 tokens are known limitations"
    }
  },
  "conditional_scope": {
    "automation_infrastructure": {
      "in_scope": false,
      "reason": "Automation roles (forwarder) are considered trusted; automation triggering logic is out of scope"
    },
    "oracle_verification": {
      "in_scope": false,
      "reason": "Cryptographic verification of Data Streams reports is delegated to external verifier contract (out of scope)"
    }
  },
  "trust_assumptions": {
    "admin_roles": {
      "trust_level": "TRUSTED",
      "description": "DEFAULT_ADMIN_ROLE and role managers",
