      "trust_level": "TRUSTED",
      "description": "WorkflowRouter forwarder role that submits reports and triggers auctions",
      "in_scope_for_bug_bounty": false,
      "note": "Automation infrastructure is trusted; roles assigned to it are privileged"
    },
    "bidders": {
      "trust_level": "UNTRUSTED",
      "description": "Permissionless auction bidders calling bid()",
      "in_scope_for_bug_bounty": true,
      "note": "Any address can bid; callback execution and reentrancy risks apply"
    },
    "cowswap_solvers": {
      "trust_level": "UNTRUSTED",
      "description": "CowSwap solvers interacting via GPV2CompatibleAuction",
      "in_scope_for_bug_bounty": true,
      "note": "Solvers are external and permissionless"
    },
    "price_feeds": {
      "trust_level": "SEMI_TRUSTED",
      "description": "Data Streams price feeds submitted via PriceManager.transmit()",
      "in_scope_for_bug_bounty": true,
      "note": "Feed data is verified by external verifier (out of scope), but staleness and manipulation within PriceManager logic is in scope"
    }
  },
  "severity_classification": {
    "Critical": {
      "impact": "Direct theft or permanent freezing of funds",
      "examples": [
        "Drain auction contract funds via bid manipulation",
        "Bypass price curve to buy assets at near-zero cost"
      ]
    },
    "High": {
      "impact": "Significant loss of funds or protocol value extraction",
      "examples": [
        "Rounding errors enabling systematic value extraction",
        "Reentrancy via callback leading to double-spend",
        "Price manipulation enabling unfair auction outcomes"
      ]
    },
    "Medium": {
      "impact": "Conditional loss of funds, DoS of core functionality, or broken invariants",
      "examples": [
        "Auction participation blocking (DoS)",
        "Slippage threshold bypass under specific conditions",
        "Stale price data enabling unfavorable trades"
      ]
    },
    "Low": {
      "impact": "Minor issues, informational, or gas optimizations",
      "examples": [
        "Event emission issues",
        "Non-critical rounding imprecision",
        "Gas inefficiencies"
      ]
    },
    "Informational": {
      "impact": "Best practice recommendations",
      "examples": [
        "Code style improvements",
        "Documentation gaps"
      ]
    }
  },
  "publicly_known_issues": [
    "Non-canonical ERC20s (fee-on-transfer, rebasing, non-approve-0) are not supported",
    "Arbitrary deposits during live auctions: balance-based amount detection means extra deposits are only available to bid() callers, not CowSwap solvers. Accepted as net positive.",
    "CowSwap order staleness: limit orders may have higher price than on-chain auction value due to periodic updates. Failed solver orders possible when non-CowSwap bidder reduces balance."
  ]
}

